using System;
using System.IO;
using System.Data.SqlClient;
using System.Windows.Forms;

namespace FileUploader
{
    public partial class MainForm : Form
    {
        public MainForm()
        {
            InitializeComponent();
        }

        private void btnUpload_Click(object sender, EventArgs e)
        {
            string folderPath = txtFolderPath.Text;
            string username = txtUsername.Text;
            string password = txtPassword.Text;

            if (string.IsNullOrEmpty(folderPath) || string.IsNullOrEmpty(username) || string.IsNullOrEmpty(password))
            {
                MessageBox.Show("Please fill in all fields.");
                return;
            }

            try
            {
                string connectionString = $"Server=your_server;Database=your_database;User Id={username};Password={password};";
                using (SqlConnection connection = new SqlConnection(connectionString))
                {
                    connection.Open();
                    foreach (string file in Directory.GetFiles(folderPath))
                    {
                        byte[] fileBytes = File.ReadAllBytes(file);
                        string base64String = Convert.ToBase64String(fileBytes);
                        string fileName = Path.GetFileName(file);
                        string fileExtension = Path.GetExtension(file);

                        string query = "INSERT INTO Files (FileName, FileExtension, FileData) VALUES (@FileName, @FileExtension, @FileData)";
                        using (SqlCommand command = new SqlCommand(query, connection))
                        {
                            command.Parameters.AddWithValue("@FileName", fileName);
                            command.Parameters.AddWithValue("@FileExtension", fileExtension);
                            command.Parameters.AddWithValue("@FileData", base64String);
                            command.ExecuteNonQuery();
                        }
                    }
                }
                MessageBox.Show("Files uploaded successfully.");
            }
            catch (Exception ex)
            {
                MessageBox.Show($"An error occurred: {ex.Message}");
            }
        }
    }
}
